    reviews = json.load(f)

# Extract publication years and create decade mapping
book_to_decade = {}
year_counts = {}

for book in books:
    book_id = book['book_id']
    details = book.get('details', '')

    year = None
    # Pattern for "Month 1, 2020" format
    match = re.search(r'(?:January|February|March|April|May|June|July|August|September|October|November|December)[^\d]*\d{1,2}[^\d]*(\d{4})', details)
    if match:
        year = int(match.group(1))
    else:
        # Pattern for any 4-digit year 1900-2023
        match = re.search(r'\b(19\d{2}|20[0-2]\d)\b', details)
        if match:
            year = int(match.group(1))

    if year and 1900 <= year <= 2023:
        decade = f"{year//10*10}s"
        book_to_decade[book_id] = decade
        year_counts[year] = year_counts.get(year, 0) + 1

# Process reviews and aggregate by decade
decade_stats = {}  # decade -> {'books': set(), 'ratings': []}

for review in reviews:
    purchase_id = review['purchase_id']
    rating = float(review['rating'])

    # Convert purchase_id to book_id
    book_id = purchase_id.replace('purchaseid_', 'bookid_', 1)

    if book_id in book_to_decade:
        decade = book_to_decade[book_id]

        if decade not in decade_stats:
            decade_stats[decade] = {'books': set(), 'ratings': []}

        decade_stats[decade]['books'].add(book_id)
        decade_stats[decade]['ratings'].append(rating)

# Calculate average ratings for decades with at least 10 distinct books
decade_averages = []
for decade, stats in decade_stats.items():
    distinct_books = len(stats['books'])
    if distinct_books >= 10:
        avg_rating = sum(stats['ratings']) / len(stats['ratings'])
        decade_averages.append({
            'decade': decade,
            'avg_rating': round(avg_rating, 3),
            'distinct_books': distinct_books,
            'total_reviews': len(stats['ratings'])
        })

# Sort by average rating (descending)
decade_averages.sort(key=lambda x: x['avg_rating'], reverse=True)

# Output results
if decade_averages:
    best_decade = decade_averages[0]['decade']
    output = {
        'best_decade': best_decade,
        'all_decades': decade_averages
    }
else:
    output = {
        'best_decade': 'No decade found with at least 10 distinct books',
        'all_decades': []
    }

print("__RESULT__:")
print(json.dumps(output))

